iter_factor = math.ceil(Decimal(3.45) * Decimal(ema_var + 1))  #iterating over this many terms gives 99.9% of all weighting factors
iter_num = 0
ema_calc_top = 0
ema_calc_bot = 0

while (iter_num < iter_factor):  #loop to calculate EMA
  ema_calc_top_p = trade_list[iter_num] * pow((1 - (ema_smooth / (1 + ema_var))), iter_num)
  ema_calc_top = ema_calc_top + ema_calc_top_p
  ema_calc_bot_p = pow((1 - (ema_smooth / (1 + ema_var))), iter_num)
  ema_calc_bot = ema_calc_bot + ema_calc_bot_p
  ema_calc = ema_calc_top / ema_calc_bot
  iter_num = iter_num + 1
  print(iter_num)

